import React, { type FC, useEffect, useState } from "react";
import Slider from "@react-native-community/slider";
import { Text } from "react-native";
import type { ISliderProps } from "@lmb/kitsconcerto-types";
import { Flex } from "../../";

const KitsSliders: FC<ISliderProps> = ({
                                           minValue = 0,
                                           maxValue = 100,
                                           prefix,
                                           step,
                                           disabled,
                                           value,
                                           isRange = false,
                                           onChange,
                                           onSlideEnd,
                                           className,
                                       }) => {
    const isControlled = value !== undefined;

    const [localValue, setLocalValue] = useState<number | [number, number]>(
        isRange ? [minValue, maxValue] : minValue
    );

    const currentValue = isControlled ? value : localValue;

    useEffect(() => {
        if (!isControlled) {
            setLocalValue(isRange ? [minValue, maxValue] : minValue);
        }
    }, [minValue, maxValue, isRange, isControlled]);

    /* ---------------------------- RANGE MODE --------------------------- */

    if (isRange) {
        const [start, end] = Array.isArray(currentValue)
            ? currentValue
            : [minValue, maxValue];

        return (
            <Flex w="full" flexDirection="column" gap={2} className={className}>
                {/* Start thumb */}
                <Slider
                    minimumValue={minValue}
                    maximumValue={end}
                    value={start}
                    step={step}
                    disabled={disabled}
                    onValueChange={(v: number) => {
                        const next: [number, number] = [v, end];
                        isControlled ? onChange?.({value:next}) : setLocalValue(next);
                    }}
                    onSlidingComplete={(v: number) => {
                        onSlideEnd?.({
                            value: [v, end],
                        });
                    }}
                />

                {/* End thumb */}
                <Slider
                    minimumValue={start}
                    maximumValue={maxValue}
                    value={end}
                    step={step}
                    disabled={disabled}
                    onValueChange={(v: number) => {
                        const next: [number, number] = [start, v];
                        isControlled ? onChange?.({value:next}) : setLocalValue(next);
                    }}
                    onSlidingComplete={(v: number) => {
                        onSlideEnd?.({
                            value: [start, v],
                        });
                    }}
                />

                <Flex justifyContent="space-between">
                    <Text>{prefix ? `${prefix}${start}` : start}</Text>
                    <Text>{prefix ? `${prefix}${end}` : end}</Text>
                </Flex>
            </Flex>
        );
    }

    /* --------------------------- SINGLE MODE ---------------------------- */

    const numericValue =
        typeof currentValue === "number" ? currentValue : minValue;

    return (
        <Flex w={'full'} flexDirection="column" gap={2} className={className}>
            <Slider
                minimumValue={minValue}
                maximumValue={maxValue}
                step={step}
                disabled={disabled}
                value={numericValue}
                onValueChange={(v: number) => {
                    isControlled ? onChange?.({value:v}) : setLocalValue(v);
                }}
                onSlidingComplete={(v: number) => {
                    onSlideEnd?.({
                        value: v,
                    });
                }}
            />

            <Flex justifyContent="flex-end">
                <Text>{prefix ? `${prefix}${numericValue}` : numericValue}</Text>
            </Flex>
        </Flex>
    );
};

export default KitsSliders;
